mapper.sql:
from advisor_product p left join ( select n1.product_id, n1.nav, n1.cum_return from advisor_product_nav n1 inner join ( select product_id, max(nav_date) as max_nav_date from advisor_product_nav group by product_id ) latest on latest.product_id = n1.product_id and latest.max_nav_date = n1.nav_date ) nav on nav.product_id = p.id where p.status = 'PUBLISHED' and p.published_version_no is not null
and ( p.name like concat('%', #{keyword}, '%') or p.strategy_code like concat('%', #{keyword}, '%') )
and p.type = #{type}
and p.risk_level = #{riskLevel}

mapper.select:
select count(1)
from advisor_product p
where p.status = 'PUBLISHED'
  and p.published_version_no is not null

    and (
        p.name like concat('%', #{keyword}, '%')
        or p.strategy_code like concat('%', #{keyword}, '%')
    )


    and p.type = #{type}


    and p.risk_level = #{riskLevel}
